function.arguments:
{"cmd": "docker run --rm --network mvn-cache --entrypoint bash j21-fitness:latest -c "
# Try to download the missing JARs from nexus with shorter timeout
curl -s --connect-timeout 5 --max-time 10 -o /tmp/kafka-schema-registry-client-7.0.0.jar http://nexus:8081/repository/maven-public/io/confluent/kafka-schema-registry-client/7.0.0/kafka-schema-registry-client-7.0.0.jar
echo 'kafka-schema-registry-client size:' \$(stat -c%s /tmp/kafka-schema-registry-client-7.0.0.jar 2>/dev/null || echo 'failed')
curl -s --connect-timeout 5 --max-time 10 -o /tmp/kafka-avro-serializer-7.0.0.jar http://nexus:8081/repository/maven-public/io/confluent/kafka-avro-serializer/7.0.0/kafka-avro-serializer-7.0.0.jar
echo 'kafka-avro-serializer size:' \$(stat -c%s /tmp/kafka-avro-serializer-7.0.0.jar 2>/dev/null || echo 'failed')
" 2>&1", "timeout_seconds": 30}
